package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testPrint() throws IOException, NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        StringWriter out = new StringWriter();
        Object object = null;
        CharSequence value = "test";
        int offset = 0;
        int len = value.length();
        boolean newRecord = true;

        // When
        Method method = CSVFormat.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class, Appendable.class, boolean.class);
        method.setAccessible(true);
        method.invoke(csvFormat, object, value, offset, len, out, newRecord);

        // Then
        assertEquals("test", out.toString());
    }

    @Test
    void testPrintWithObject() throws IOException, NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        StringWriter out = new StringWriter();
        Object object = 123;
        CharSequence value = "test";
        int offset = 0;
        int len = value.length();
        boolean newRecord = false;

        // When
        Method method = CSVFormat.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class, Appendable.class, boolean.class);
        method.setAccessible(true);
        method.invoke(csvFormat, object, value, offset, len, out, newRecord);

        // Then
        assertEquals(',' + "test", out.toString());
    }

    @Test
    void testPrintAndQuote() throws IOException, NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        StringWriter out = new StringWriter();
        Object object = 123;
        CharSequence value = "test";
        int offset = 0;
        int len = value.length();
        boolean newRecord = false;

        // When
        Method method = CSVFormat.class.getDeclaredMethod("printAndQuote", Object.class, CharSequence.class, int.class, int.class, Appendable.class, boolean.class);
        method.setAccessible(true);
        method.invoke(csvFormat, object, value, offset, len, out, newRecord);

        // Then
        assertEquals("\",test\"", out.toString());
    }

    @Test
    void testPrintAndEscape() throws IOException, NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        StringWriter out = new StringWriter();
        CharSequence value = "te,st";
        int offset = 0;
        int len = value.length();

        // When
        Method method = CSVFormat.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class, Appendable.class);
        method.setAccessible(true);
        method.invoke(csvFormat, value, offset, len, out);

        // Then
        assertEquals("te\\,st", out.toString());
    }
}
